/* ŚĮĻŤĮĚś°Üś†∑ŚľŹ */
.user-detail-dialog >>> .el-dialog__header {
	background: #fafbfc;
	padding: 20px;
	border-bottom: 1px solid #ebeef5;
}

.user-detail-dialog >>> .el-dialog__title {
	font-size: 16px;
	font-weight: 600;
	color: #303133;
}

.user-detail-dialog >>> .el-dialog__body {
	padding: 0;
}

.user-detail-dialog >>> .el-dialog__footer {
	padding: 15px 20px;
	border-top: 1px solid #ebeef5;
	background: #fafbfc;
	text-align: center;
}

/* ŚÜÖŚģĻŚĆļŚüü */
.detail-content {
	padding: 20px;
	max-height: 500px;
	overflow-y: auto;
}

/* śĽöŚä®śĚ°ÁĺéŚĆĖ */
.detail-content::-webkit-scrollbar {
	width: 6px;
}

.detail-content::-webkit-scrollbar-track {
	background: #f5f5f5;
	border-radius: 3px;
}

.detail-content::-webkit-scrollbar-thumb {
	background: #c0c4cc;
	border-radius: 3px;
}

.detail-content::-webkit-scrollbar-thumb:hover {
	background: #909399;
}

/* šŅ°śĀĮŚĆļŚĚó */
.info-section {
	background: #ffffff;
	border-radius: 8px;
	border: 1px solid #ebeef5;
	margin-bottom: 16px;
	padding: 16px;
}

.info-section:last-child {
	margin-bottom: 0;
}

/* ŚĆļŚĚóś†áťĘė */
.section-title {
	display: flex;
	align-items: center;
	gap: 8px;
	font-size: 15px;
	font-weight: 600;
	color: #303133;
	margin-bottom: 16px;
	padding-bottom: 12px;
	border-bottom: 2px solid #f0f0f0;
}

.section-title i {
	color: #409eff;
	font-size: 16px;
}

/* šŅ°śĀĮŤ°Ć */
.info-row {
	margin-bottom: 12px;
}

.info-row:last-child {
	margin-bottom: 0;
}

/* šŅ°śĀĮť°Ļ */
.info-item {
	display: flex;
	align-items: center;
	padding: 8px 0;
}

.info-item .label {
	color: #606266;
	font-size: 14px;
	font-weight: 500;
	min-width: 85px;
	flex-shrink: 0;
}

.info-item .value {
	color: #303133;
	font-size: 14px;
	flex: 1;
	word-break: break-all;
}

/* ŚõĺÁČáť°Ļ */
.image-item {
	text-align: center;
}

.image-label {
	color: #606266;
	font-size: 14px;
	font-weight: 500;
	margin-bottom: 12px;
}

.image-container {
	display: flex;
	justify-content: center;
	align-items: center;
	min-height: 120px;
}

.user-image {
	width: 100px;
	height: 100px;
	border-radius: 8px;
	border: 2px solid #ebeef5;
	cursor: pointer;
	transition: all 0.3s ease;
}

.user-image:hover {
	border-color: #409eff;
	transform: scale(1.05);
	box-shadow: 0 2px 8px rgba(64, 158, 255, 0.3);
}

.no-image {
	width: 100px;
	height: 100px;
	border-radius: 8px;
	border: 2px dashed #dcdfe6;
	display: flex;
	flex-direction: column;
	justify-content: center;
	align-items: center;
	gap: 8px;
	background: #fafbfc;
	color: #909399;
}

.no-image i {
	font-size: 32px;
}

.no-image span {
	font-size: 12px;
}

/* ŚļēťÉ®śĆČťíģ */
.dialog-footer .el-button {
	min-width: 100px;
}
